# ── Cabeçalho ────────────────────────────────────────────────────────
st.markdown("""
<div class="header-box">
    <h1>📊 PROCESSADOR DE CONTAS A RECEBER</h1>
    <p>Selecione a empresa, faça upload dos arquivos e baixe o Excel pronto.</p>
</div>
""", unsafe_allow_html=True)

# ── Seletor de empresa ───────────────────────────────────────────────
st.markdown("#### Selecione a empresa")

col1, col2 = st.columns(2)

empresa = st.session_state.get("empresa", None)

with col1:
    active_mx = "active-mx" if empresa == "maxifrota" else ""
    st.markdown(f"""
    <div class="selector-card {active_mx}">
        <img src="data:image/jpeg;base64,{LOGO_MX}" />
        <p>CR MAXIFROTA</p>
    </div>
    """, unsafe_allow_html=True)
    if st.button("Selecionar MaxiFrota", use_container_width=True, key="btn_mx"):
        st.session_state["empresa"] = "maxifrota"
        st.rerun()

with col2:
    active_nc = "active-nc" if empresa == "nutricash" else ""
    st.markdown(f"""
    <div class="selector-card {active_nc}">
        <img src="data:image/jpeg;base64,{LOGO_NC}" />
        <p>CR NUTRICASH</p>
    </div>
    """, unsafe_allow_html=True)
    if st.button("Selecionar Nutricash", use_container_width=True, key="btn_nc"):
        st.session_state["empresa"] = "nutricash"
        st.rerun()

empresa = st.session_state.get("empresa", None)

if not empresa:
    st.info("👆 Selecione uma empresa para começar.")
    st.markdown('<div class="footer">MaxiFrota & Nutricash · Processador CR · 2026</div>', unsafe_allow_html=True)
    st.stop()

st.markdown('<hr class="divider">', unsafe_allow_html=True)

# ── Config por empresa ───────────────────────────────────────────────
if empresa == "maxifrota":
    cfg = {
        "titulo"    : "MaxiFrota — CR",
        "csv_label" : "CRMX.CSV — dados brutos do sistema",
        "csv_nome"  : "CRMX.CSV",
        "xlsx_label": "CR_MAXIFROTA_2026.XLSX — planilha anterior",
        "xlsx_nome" : "CR_MAXIFROTA_2026.XLSX",
        "logo"      : LOGO_MX,
        "out_prefix": "CR_MAXIFROTA_PROCESSADO",
        "cor"       : "#00205B",
    }
else:
    cfg = {
        "titulo"    : "Nutricash — CR",
        "csv_label" : "CRNC.CSV — dados brutos do sistema",
        "csv_nome"  : "CRNC.CSV",
        "xlsx_label": "CR_NUTRICASH_2026.XLSX — planilha anterior",
        "xlsx_nome" : "CR_NUTRICASH_2026.XLSX",
        "logo"      : LOGO_NC,
        "out_prefix": "CR_NUTRICASH_PROCESSADO",
        "cor"       : "#1C2B5A",
    }

logo_html = f'<img src="data:image/jpeg;base64,{cfg["logo"]}" style="height:48px;margin-bottom:8px;">' 
st.markdown(f'<div style="text-align:center">{logo_html}<h3 style="color:{cfg["cor"]};margin:0">{cfg["titulo"]}</h3></div>', unsafe_allow_html=True)
st.markdown("<br>", unsafe_allow_html=True)

# ── Instruções ───────────────────────────────────────────────────────
with st.expander("📖 Como usar — clique para ver", expanded=False):
    st.markdown(f"""
    <div class="step">
        <div class="step-num">1</div>
        <div class="step-txt">Selecione o arquivo <strong>{cfg["csv_nome"]}</strong> — exportado do sistema.</div>
    </div>
    <div class="step">
        <div class="step-num">2</div>
        <div class="step-txt">Selecione o arquivo <strong>{cfg["xlsx_nome"]}</strong> — planilha do mês anterior com histórico dos clientes.</div>
    </div>
    <div class="step">
        <div class="step-num">3</div>
        <div class="step-txt">Clique em <strong>⚡ PROCESSAR PLANILHA</strong> e aguarde. O Excel é gerado com 4 abas:<br>
        <strong>RESUMO A VENCER · RESUMO VENCIDOS · A VENCER · VENCIDOS</strong><br>
        Células em <span style="color:red;font-weight:bold">REVISAR</span> indicam clientes novos sem histórico.</div>
    </div>
    """, unsafe_allow_html=True)

st.markdown("<br>", unsafe_allow_html=True)

# ── Uploads ──────────────────────────────────────────────────────────
col1, col2 = st.columns(2)

with col1:
    st.markdown(f'''
    <div class="upload-card">
        <h4>📄 Arquivo 1</h4>
        <p>{cfg["csv_label"]}</p>
    </div>''', unsafe_allow_html=True)
    csv_file = st.file_uploader(
        "CSV", type=["csv"], key=f"csv_{empresa}", label_visibility="collapsed")
    if csv_file:
        st.success(f"✅ {csv_file.name}  ({csv_file.size // 1024} KB)")

with col2:
    st.markdown(f'''
    <div class="upload-card">
        <h4>📊 Arquivo 2</h4>
        <p>{cfg["xlsx_label"]}</p>
    </div>''', unsafe_allow_html=True)
    xlsx_file = st.file_uploader(
        "XLSX", type=["xlsx","xls"], key=f"xlsx_{empresa}", label_visibility="collapsed")
    if xlsx_file:
        st.success(f"✅ {xlsx_file.name}  ({xlsx_file.size // 1024} KB)")

st.markdown("<br>", unsafe_allow_html=True)

if not (csv_file and xlsx_file):
    st.info("⬆️  Faça upload dos dois arquivos para habilitar o processamento.")

processar = st.button(
    "⚡  PROCESSAR PLANILHA",
    disabled=not (csv_file and xlsx_file),
    use_container_width=True,
)

# ── Processamento ────────────────────────────────────────────────────
if processar and csv_file and xlsx_file:
    progress = st.progress(0, text="Iniciando...")
    try:
        import contextlib, io as _io

        progress.progress(15, text="📂 Lendo os arquivos...")
        csv_bytes  = csv_file.read()
        xlsx_bytes = xlsx_file.read()

        progress.progress(30, text="📊 Processando dados...")

        log_buffer = _io.StringIO()
        with contextlib.redirect_stdout(log_buffer):
            if empresa == "maxifrota":
                from core import process_files
                result_bytes = process_files(csv_bytes, xlsx_bytes)
            else:
                from core_nutricash import process_files_nutricash
                result_bytes = process_files_nutricash(csv_bytes, xlsx_bytes)

        progress.progress(95, text="📝 Finalizando Excel...")
        ts       = datetime.now().strftime("%Y%m%d_%H%M%S")
        out_name = f'{cfg["out_prefix"]}_{ts}.xlsx'
        progress.progress(100, text="✅ Concluído!")

        st.markdown("""
        <div class="success-box">
            <h3>🎉 Planilha gerada com sucesso!</h3>
            <p>Clique no botão abaixo para baixar o arquivo Excel.</p>
        </div>
        """, unsafe_allow_html=True)
        st.markdown("<br>", unsafe_allow_html=True)

        st.download_button(
            label="📥  BAIXAR EXCEL PROCESSADO",
            data=result_bytes,
            file_name=out_name,
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            use_container_width=True,
        )

        log_text = log_buffer.getvalue()
        if log_text.strip():
            with st.expander("📋 Log do processamento", expanded=False):
                st.code(log_text, language=None)

    except Exception as e:
        import traceback
        progress.empty()
        st.markdown(f"""
        <div class="error-box">
            <strong>❌ Erro durante o processamento</strong><br><br>{str(e)}
        </div>
        """, unsafe_allow_html=True)
        with st.expander("🔍 Detalhes do erro"):
            st.code(traceback.format_exc())

st.markdown('<div class="footer">MaxiFrota & Nutricash · Processador CR · 2026</div>', unsafe_allow_html=True)
